{
  "name": "State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to anyone eligible for Medicare (typically age 65+ or under 65 with certain disabilities), family members, and caregivers. Also supports those with limited incomes or dually eligible for Medicare/Medicaid, but no specific dollar thresholds apply for SHIP access itself[1][2][5]",
    "asset_limits": "No asset limits or tests[1][2]",
    "other_requirements": ["Medicare eligibility (current or soon-to-be)", "Family members and caregivers of Medicare beneficiaries also qualify", "No residency restrictions beyond Alaska state program access[1][2][5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one counseling and assistance on Medicare coverage options (Parts A, B, C, D), Medigap, Medicare Savings Programs, Extra Help/Low-Income Subsidy, Medicaid applications, appeal rights, long-term care insurance, and fraud prevention via Senior Medicare Patrol (SMP). Includes in-person, phone, or virtual sessions; public education presentations; outreach at health fairs and events. No dollar amounts, fixed hours, or in-kind benefits—unlimited personalized help as needed[1][2][3][4][8][10]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-478-6065 (in-state toll-free), TTY: 1-800-770-8973, Anchorage/direct: 907-269-3680", "Email: doh.mio.info@alaska.gov", "Website: https://health.alaska.gov/en/senior-and-disabilities-services/medicare-office/ or https://dhss.alaska.gov/pages/default.aspx (Alaska DHSS)", "In-person or local counseling: Schedule via phone; network of local sites via state partnerships", "National locator: shiphelp.org for Alaska-specific contacts[5][6][7][8]"],
    "processing_time": "Immediate counseling available upon contact; no formal application processing as it's not enrollment-based[1][5]",
    "waitlist": null,
    "forms": ["No specific forms required; counselors request relevant Medicare documents during sessions (e.g., Medicare card, current plan details)[1]"],
    "documents": ["Medicare card/ID", "Current Medicare plan documents", "Prescription drug list", "Other insurance info", "Income details if applying for savings programs like Extra Help (prepared but not required for SHIP access itself)[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Delivered statewide via Alaska Department of Health (Medicare Information Office) in partnership with local Area Agencies on Aging and community sites; locally focused counseling reflects regional Medicare options, but no explicit differences in services, wait times, or providers by region noted[2][4][5][8]",
    "offices_or_providers": ["Primary: Alaska Medicare Information Office (Anchorage-based, statewide service)", "Local network via state partnerships (over 2,200 national sites, Alaska-specific via shiphelp.org locator)[2][4][5]"]
  },
  "official_source": "https://health.alaska.gov/en/senior-and-disabilities-services/medicare-office/",
  "gotchas": ["Not a healthcare or financial aid program—provides counseling only, not direct payment or treatment", "Must be Medicare-related; won't help with non-Medicare insurance", "Services are free but rely on appointments; contact early (e.g., 3 months before Medicare starts)", "People miss that family/caregivers can access without being beneficiaries themselves", "Out-of-state callers use Anchorage number[1][2][5][8]"],
  "data_shape_notes": "no income/asset test; open to all Medicare-eligible plus families/caregivers; counseling-only service via statewide office with local delivery network; no waitlists or caps"
}

{
  "name": "Meals on Wheels (Senior Meals Program)",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits; income is not a factor in determining eligibility[3][4][8]",
    "asset_limits": "No asset limits mentioned in available sources",
    "other_requirements": ["Physically limited in ability to independently carry out activities of daily living, such as mobility challenges making it hard to shop for food, prepare meals, or socialize[1][3]", "For home-delivered meals in some areas (e.g., North Slope), doctor's note stating homebound or disabled[8]", "Complete client profile or application[3][5][8]"]
  },
  "benefits": {
    "type": "service",
    "value": "Home-delivered hot meals (daily, with frozen meals for weekends/holidays in some areas); congregate/group meal sites with hot nutritious lunch; each meal contains one-third of daily nutritional requirements; opportunities for socialization[3][4][8]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Phone: Salvation Army Anchorage (907) 349-0613[3]", "Phone: Fairbanks Senior Center (907) 452-1735[5]", "Phone: North Slope Borough Senior Program (907) 852-0276[8]", "In-person: Complete client profile at meal site (e.g., Cook Inlet Housing, 9131 Centennial Circle, Anchorage)[3]", "Forms: MOW and Nutritional forms (Fairbanks, write-able PDFs)[5]", "Contact local provider for assessment and exact steps; referrals from doctor or social worker may be required[1]"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": ["Client profile[3][4]", "MOW and Nutritional forms (Fairbanks)[5]", "Senior program application (North Slope)[8]"],
    "documents": ["Doctor's note for home-delivered meals if homebound/disabled (North Slope)[8]", "Referral letter from doctor or social worker (may be required by some providers)[1]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Varies by local provider and region; not uniformly available statewide",
    "regional_variations": "Anchorage (Salvation Army: home-delivered and group meals, no income test)[3]; Fairbanks (Senior Center: home-delivered)[5]; North Slope Borough (requires doctor's note for home-delivery)[8]; Southeast Alaska (SESS: 12 senior centers for congregate and home-delivered)[9]; Wasilla (WASI provider)[7]",
    "offices_or_providers": ["Salvation Army, Anchorage[3]", "Fairbanks Senior Center[5]", "North Slope Borough, Utqiagvik[8]", "SESS senior centers in Southeast Alaska[9]", "WASI, Wasilla[7]"]
  },
  "official_source": "https://health.alaska.gov/ (Alaska DHSS for state regulations); local providers via https://www.mealsonwheelsamerica.org/find-meals-and-services/[1][2]",
  "gotchas": ["Eligibility and requirements vary significantly by local provider and region (e.g., doctor's note required in North Slope but not mentioned elsewhere)[8]", "Meals may be free with suggested donations, but confirm with local provider as payment could be on sliding scale[1]", "Primarily for those 60+ with mobility/physical limitations; not automatic for all seniors[1][3]", "Contact State Unit on Aging if no local provider[1]", "Program administered by local non-profits and boroughs under state regs, not centralized state application[2]"],
  "data_shape_notes": "Decentralized by region with different providers (e.g., Salvation Army in Anchorage, senior centers elsewhere); no statewide income/asset tests; varies by home-delivered vs. congregate; doctor's note for home-delivery in some areas only"
}

{
  "name": "Alzheimer's Family Caregiver Support Program",
  "eligibility": {
    "age": null,
    "income_limits": "Income and asset limits apply for CSRCP (specific dollar amounts and household size tables not detailed in sources; financial eligibility required for care recipient with Alzheimer's diagnosis)[1]",
    "asset_limits": "Asset limits apply for CSRCP (details on what counts or exemptions not specified in sources)[1]",
    "other_requirements": [
      "Care recipient must have a formal diagnosis of Alzheimer's disease or a related dementia (required for CSRCP)[1]",
      "Caregiver must be providing unpaid care (CSRCP and NFCSP)[1]",
      "For NFCSP: Care recipient 60+ or with Alzheimer's (any age); or caregiver 60+ caring for adult child with disability; or grandparents/relatives 55+ raising grandchildren[1][2][3]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Respite care (adult day and in-home options, no cap on services); information and assistance; individual counseling; support groups; caregiver training; limited supplemental services (e.g., transportation, home modifications); educational materials, referrals for Alzheimer's[1][2][3]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Fillable application form via Anchorage Older Americans Services Commission (AOASCC): https://www.aoascc.org/Customer-Content/www/CMS/files/Caregiver_Support_Services_Application-Fillable_Combined_2025_05_19.pdf[1]",
      "Access FCSP through Alaska Home & Community Based Senior Grants website (specific URL: http://dhss.alaska.gov/dsds/Pages/hcb/hcb.aspx)[2]",
      "Contact local grantees of Alaska Department of Health and Social Services, Division of Senior and Disabilities Services[3]"
    ],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": [
      "Caregiver Support Services Application (Fillable Combined, dated 2025_05_19)[1]"
    ],
    "documents": [
      "Completed Application Form[1]",
      "Proof of Diagnosis (physician’s note, medical record, or official documentation confirming Alzheimer’s or related dementia; required for CSRCP)[1]",
      "Proof of Age (if required: driver’s license, birth certificate, or state ID)[1]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered statewide by Alaska Department of Health and Social Services, Division of Senior and Disabilities Services, and locally by grantees; Alzheimer's Resource Agency in four locations; other services in 12 communities[3]",
    "offices_or_providers": [
      "Local grantees of Division of Senior and Disabilities Services[3]",
      "Alzheimer’s Disease Resource Agency (four locations)[3]"
    ]
  },
  "official_source": "https://dhss.alaska.gov/dsds/Pages/hcb/hcb.aspx",
  "gotchas": [
    "Two related programs: CSRCP (Alzheimer's-specific with income/asset limits and diagnosis proof) vs. broader NFCSP (age 60+ focus, varying eligibility)[1][2]",
    "Spouses and legal guardians often ineligible as paid caregivers in related programs[2]",
    "Financial eligibility strictly required for CSRCP but details like exact income/asset thresholds and exemptions not publicly detailed in sources[1]",
    "Must distinguish from Medicaid programs like ALI Waiver (waitlist, different eligibility)[2][6]"
  ],
  "data_shape_notes": "Dual structure: CSRCP (diagnosis + financial test) and NFCSP (age-based, no min caregiver age); local grantees vary services; no service caps but supplemental limited; income/asset limits exist without published tables"
}

{
  "name": "Alaska Legal Services Corporation (ALSC) Senior Legal Hotline",
  "eligibility": {
    "age": 60,
    "income_limits": "For seniors over 60 via Elder Advocacy, assistance may be provided without regard to income, with priority to those in social or economic need. General ALSC income eligibility (125% Federal Poverty Guidelines for Alaska) applies if needed: Household Size 1: Yearly $24,938 / Monthly $2,078 / Weekly $480; 2: $33,813 / $2,818 / $650; 3: $42,688 / $3,557 / $821; 4: $51,563 / $4,297 / $992; 5: $60,438 / $5,037 / $1,162; 6: $69,313 / $5,776 / $1,333; 7: $78,188 / $6,516 / $1,504; 8: $87,063 / $7,255 / $1,674; Each additional: $8,875 / $740 / $171.[1][7]",
    "asset_limits": "Assets are considered in eligibility screening (gross household assets asked during intake), but no specific dollar limits or exemptions detailed.[2]",
    "other_requirements": ["Alaska resident", "Civil legal issue in priority areas (e.g., income maintenance, housing, health care for seniors)", "No conflicts of interest", "Case must align with office priorities; not all cases accepted due to limited resources.[1][3][7]"]
  },
  "benefits": {
    "type": "service",
    "value": "Legal assistance and advice, court/administrative representation, referrals; community education/training via clinics/outreach. Specific senior areas: Income maintenance (Alaska Senior Assistance, Social Security, SSI, Adult Public Assistance, Food Stamps), housing (landlord/tenant, public housing, assisted living, nursing homes), health care (Medicaid, Medicare, Long-Term Care, PCA program). No specified dollar amounts or hours.[7]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: ALSC Online Eligibility Interview at https://www.alsc-law.org/intake/", "Phone: Statewide intake line 1-888-478-2572", "Mail/In-person: Paper applications (English, Samoan, Tagalog, Spanish, German, Russian) at nearest ALSC office (e.g., Anchorage, Bethel, Dillingham, Juneau).[2][3][5][6]"],
    "processing_time": "Intake specialist contacts within two business days after online interview; phone/paper similar process.[2]",
    "waitlist": "No guaranteed assistance due to limited resources; case staffing attempted if eligible, but not all accepted.[3]",
    "forms": ["ALSC Online Eligibility Interview", "Paper Application for each ALSC office.[2][5]"],
    "documents": ["Information on legal issue(s), gross household income, assets, phone/email for contact, papers about legal problem.[2][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Alaska residents only",
    "regional_variations": "Case acceptance priorities set by each office (e.g., Anchorage, Bethel, Dillingham, Juneau); contact nearest office for specifics. No detailed wait time or service differences noted.[1][7][8]",
    "offices_or_providers": ["Anchorage: 1016 West Sixth Ave, Suite 200, 907-272-9431 / 1-888-478-2572", "Bethel: PO Box 248, 460 Ridgecrest Dr, Suite 113, 907-543-2237 / 1-800-478-2230", "Dillingham", "Juneau: 8711 Teal St, Suite 203, 907-586-6425 / 1-800-789-6426.[8]"]
  },
  "official_source": "https://www.alsc-law.org/elder-advocacy/",
  "gotchas": ["Not a 'hotline' but Elder Advocacy program accessed via general ALSC intake; no income test guaranteed for seniors but priority-based and resources limited—not all cases accepted.", "No criminal cases, personal injury, accidents, or wrongful death.", "Must complete full application; conflicts or non-priority cases referred elsewhere.", "Seniors get priority but still subject to office priorities and availability.[1][3][6][7]"],
  "data_shape_notes": "Income often waived for seniors 60+ with priority to need; services via statewide intake but office-specific priorities; no fixed hours/dollars, case-by-case acceptance."
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": 60,
