  },
  "application": {
    "methods": ["Phone: 907-334-4480 or toll-free 1-800-730-6393 (M-F 8:00 a.m. to 4:30 p.m.)", "Online complaint form: akoltco.org", "Address: 3745 Community Park Loop, Suite 200, Anchorage, AK 99508", "Fax: 907-334-4486"],
    "processing_time": "Not specified in available data; complaint investigations handled promptly by certified ombudsmen.",
    "waitlist": null,
    "forms": ["Online Complaint form at akoltco.org"],
    "documents": ["No specific documents required for initial contact; details of complaint (e.g., facility name, issue description) recommended for intake"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all long-term care facilities statewide.",
    "regional_variations": "Volunteers trained and supervised statewide to provide local services; all skilled nursing facilities and senior licensed assisted living homes visited at least once per year; central office in Anchorage with statewide toll-free access.",
    "offices_or_providers": ["Main office: 3745 Community Park Loop, Suite 200, Anchorage, AK 99508", "Statewide volunteer network"]
